from collections import defaultdict
import numpy as np

def build_cooccurrence(sentences, vocab, window=2):
    word2idx = {w: i for i, w in enumerate(vocab)}
    V = len(vocab)
    matrix = np.zeros((V, V), dtype=np.float32)

    for sent in sentences:
        tokens = [w for w in sent if w in word2idx]
        for center_pos, center in enumerate(tokens):
            ci = word2idx[center]
            for offset in range(-window, window + 1):
                if offset == 0:
                    continue
                ctx_pos = center_pos + offset
                if 0 <= ctx_pos < len(tokens):
                    cj = word2idx[tokens[ctx_pos]]
                    matrix[ci, cj] += 1
    return matrix

