import numpy as np
from collections import defaultdict
from sklearn.decomposition import TruncatedSVD

# Step 1: Build a vocabulary from the corpus
def build_vocab(sentences, min_count=2):
    counts = defaultdict(int)
    for sent in sentences:
        for w in sent:
            counts[w] += 1
    vocab = [w for w, c in counts.items() if c >= min_count]
    word2idx = {w: i for i, w in enumerate(vocab)}
    return vocab, word2idx

# Step 2: Build co-occurrence matrix
def cooccurrence_matrix(sentences, word2idx, window=4):
    V = len(word2idx)
    C = np.zeros((V, V), dtype=np.float32)
    for sent in sentences:
        tokens = [w for w in sent if w in word2idx]
        for center, w in enumerate(tokens):
            i = word2idx[w]
            for offset in range(1, window + 1):
                for sign in (-1, 1):
                    ctx = center + sign * offset
                    if 0 <= ctx < len(tokens):
                        j = word2idx[tokens[ctx]]
                        # weight by 1/distance (harmonic window)
                        C[i, j] += 1.0 / offset
    return C

# Step 3: PPMI transform
def ppmi(C):
    total = C.sum()
    row_marginals = C.sum(axis=1, keepdims=True) + 1e-9
    col_marginals = C.sum(axis=0, keepdims=True) + 1e-9
    pmi = np.log2((C * total) / (row_marginals * col_marginals) + 1e-9)
    return np.maximum(pmi, 0)

# Step 4: SVD to dense embeddings
def svd_embeddings(ppmi_matrix, d=100):
    svd = TruncatedSVD(n_components=d, random_state=0)
    U = svd.fit_transform(ppmi_matrix)          # shape (V, d)
    sigma = np.sqrt(svd.singular_values_)        # shape (d,)
    return U * sigma                              # scale by sqrt(sigma)

# Full pipeline
sentences = [s.lower().split() for s in [
    "the cat sat on the mat near the river bank",
    "the bank approved the loan for the new house",
    "cat and dog are common household pets",
    "water flows along the river bank every spring",
    "the financial bank issues loans and mortgages",
]]

vocab, w2i = build_vocab(sentences, min_count=1)
C = cooccurrence_matrix(sentences, w2i, window=3)
P = ppmi(C)
E = svd_embeddings(P, d=10)

# Cosine similarity
def cosine(a, b):
    return np.dot(a, b) / (np.linalg.norm(a) * np.linalg.norm(b) + 1e-9)

for w1, w2 in [("cat", "dog"), ("bank", "river"), ("cat", "river")]:
    if w1 in w2i and w2 in w2i:
        sim = cosine(E[w2i[w1]], E[w2i[w2]])
        print(f"sim({w1}, {w2}) = {sim:.3f}")

import numpy as np
from typing import List

class QueryExpander:
    """Expand search queries using distributional nearest neighbours."""

    def __init__(self, embeddings: np.ndarray, word2idx: dict, idx2word: dict):
        norms = np.linalg.norm(embeddings, axis=1, keepdims=True) + 1e-9
        self.normed = embeddings / norms
        self.word2idx = word2idx
        self.idx2word = idx2word

    def expand(self, query: str, topk: int = 4, threshold: float = 0.6) -> List[str]:
        tokens = query.lower().split()
        expanded = set(tokens)
        for token in tokens:
            if token not in self.word2idx:
                continue
            idx = self.word2idx[token]
            q = self.normed[idx]
            scores = self.normed @ q
            for i in np.argsort(-scores)[1:topk + 5]:
                if scores[i] >= threshold:
                    expanded.add(self.idx2word[i])
                if len(expanded) >= len(tokens) + topk:
                    break
        return list(expanded)

